#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>
#define MAX_N 50000
#define MAX_M 100000

// Structure to represent a graph edge
typedef struct {
    int src;
    int dest;
} Edge;

// Function to perform DFS traversal
bool dfs(int node, int *visited, int *permutation, int index, Edge *edges, int m) {
    visited[node] = 1;
    if (index >= permutation[0]) return true;
    for (int i = 0; i < m; i++) {
        if (edges[i].src == node && !visited[edges[i].dest]) {
            if (dfs(edges[i].dest, visited, permutation, index + 1, edges, m)) return true;
        }
    }
    return false;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, m;
        scanf("%d %d", &n, &m);
        Edge *edges = (Edge *)malloc(m * sizeof(Edge));
        for (int i = 0; i < m; i++) {
            scanf("%d %d", &edges[i].src, &edges[i].dest);
        }
        int *permutation = (int *)malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            scanf("%d", &permutation[i]);
        }
        int *visited = (int *)malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) visited[i] = 0;
        if (dfs(permutation[0], visited, permutation, 1, edges, m)) printf("YES\n");
        else printf("NO\n");
        free(edges);
        free(permutation);
        free(visited);
    }
    return 0;
}

