    int src;
    int dest;
};

// Function to perform DFS traversal
bool dfs(int node, vector<bool> &visited, vector<int> &permutation, int index, vector<Edge> &edges) {
    visited[node] = true;
    if (index >= permutation.size()) return true;
    for (Edge edge : edges) {
        if (edge.src == node && !visited[edge.dest]) {
            if (dfs(edge.dest, visited, permutation, index + 1, edges)) return true;
        }
    }
    return false;
}

