    static final int MAX_M = 100000;
    // Structure to represent a graph edge
    static class Edge {
        int src;
        int dest;
        Edge(int src, int dest) {
            this.src = src;
            this.dest = dest;
        }
    }
    // Function to perform DFS traversal
    static boolean dfs(int node, boolean[] visited, int[] permutation, int index, Edge[] edges) {
        visited[node] = true;
        if (index >= permutation.length) return true;
        for (Edge edge : edges) {
            if (edge.src == node && !visited[edge.dest]) {
                if (dfs(edge.dest, visited, permutation, index + 1, edges)) return true;
            }
        }
        return false;
    }
